import AsyncStorage from '@react-native-async-storage/async-storage';

const DATA_MANAGER_KEY = 'localDataManager';

class LocalDataManager {
  static async saveUserData(key, value) {
    try {
      const data = await AsyncStorage.getItem(DATA_MANAGER_KEY);
      let localData = JSON.parse(data) || {};

      if (key === 'tokens') {
        localData.tokens = value;
      } else if (key === 'profile') {
        localData.profile = value;
      } else if (key === 'settings') {
        localData.settings = value;
      }

      await AsyncStorage.setItem(DATA_MANAGER_KEY, JSON.stringify(localData));
    } catch (error) {
      console.error('Error saving data:', error);
    }
  }

  static async getUserData(key) {
    try {
      const data = await AsyncStorage.getItem(DATA_MANAGER_KEY);
      const localData = JSON.parse(data) || {};
      return localData[key] || null;
    } catch (error) {
      console.error('Error retrieving data:', error);
      return null;
    }
  }

  static async clearUserData() {
    try {
      await AsyncStorage.removeItem(DATA_MANAGER_KEY);
    } catch (error) {
      console.error('Error clearing data:', error);
    }
  }
}

export default LocalDataManager;